def triangle_area(b, h):
    return 0.5 * b * h

print(f"Rectangle 5x3: {rectangle_area(5, 3)}")
print(f"Circle r=4: {circle_area(4)}")
print(f"Triangle b=6,h=3: {triangle_area(6, 3)}")

